import{_ as e,o as a,c as i,a2 as r}from"./chunks/framework.CuEaBji2.js";const l="/nginx-reverse-emby/screenshots/panel-certificates.png",s="/nginx-reverse-emby/screenshots/panel-certificate-form.png",n="/nginx-reverse-emby/screenshots/cloudflare-token-permissions.png",k=JSON.parse('{"title":"证书与 HTTPS","description":"","frontmatter":{},"headers":[],"relativePath":"guides/certificates.md","filePath":"guides/certificates.md","lastUpdated":1782021666000}'),o={name:"guides/certificates.md"};function d(p,t,h,c,u,b){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="证书与-https" tabindex="-1">证书与 HTTPS <a class="header-anchor" href="#证书与-https" aria-label="Permalink to &quot;证书与 HTTPS&quot;">​</a></h1><p>要让访客通过 HTTPS 安全访问你的服务，你需要 TLS 证书。控制面可以自动申请、续期和管理证书，不需要手动操作命令行。</p><h2 id="三种证书来源" tabindex="-1">三种证书来源 <a class="header-anchor" href="#三种证书来源" aria-label="Permalink to &quot;三种证书来源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方式</th><th>适合场景</th></tr></thead><tbody><tr><td><strong>自动签发（HTTP-01）</strong></td><td>有域名、能开放 80/443 端口。推荐首选</td></tr><tr><td><strong>DNS-01 验证</strong></td><td>无法开放 80 端口，或需要通配符证书（<code>*.example.com</code>）</td></tr><tr><td><strong>手动上传</strong></td><td>已有商业证书或自签证书</td></tr></tbody></table><h2 id="证书管理页面" tabindex="-1">证书管理页面 <a class="header-anchor" href="#证书管理页面" aria-label="Permalink to &quot;证书管理页面&quot;">​</a></h2><p>进入 <strong>基础设施 → 证书管理</strong>。创建证书时选一个用途模板，系统会帮你填好大部分设置：</p><table tabindex="0"><thead><tr><th>模板</th><th>说明</th></tr></thead><tbody><tr><td>HTTPS 入口</td><td>给 HTTP 代理规则使用</td></tr><tr><td>Relay 监听</td><td>给 Relay 隧道监听器使用</td></tr><tr><td>混合用途</td><td>同一份证书同时用于 HTTPS 和 Relay</td></tr><tr><td>IP 证书</td><td>给 IP 地址（而非域名）签发证书</td></tr></tbody></table><p><img src="'+l+'" alt="证书管理列表"></p><p><img src="'+s+`" alt="创建证书表单"></p><h2 id="http-01-自动签发-推荐" tabindex="-1">HTTP-01 自动签发（推荐） <a class="header-anchor" href="#http-01-自动签发-推荐" aria-label="Permalink to &quot;HTTP-01 自动签发（推荐）&quot;">​</a></h2><p>最简单的方式。创建 HTTPS 入口的 HTTP 规则后，Agent 自动完成申请，无需额外配置。</p><p>前置条件：</p><ol><li>域名已解析到运行规则的 Agent 节点</li><li>Agent 节点 80 端口可访问（用于验证域名所有权）</li><li>443 端口放行（提供 HTTPS 服务）</li></ol><p>如果申请失败，去证书页面点击重试。</p><h2 id="dns-01-验证-cloudflare" tabindex="-1">DNS-01 验证（Cloudflare） <a class="header-anchor" href="#dns-01-验证-cloudflare" aria-label="Permalink to &quot;DNS-01 验证（Cloudflare）&quot;">​</a></h2><p>以下情况需要用 DNS-01：</p><ul><li>节点无法开放 80 端口（内网、端口被占用）</li><li>需要通配符证书（<code>*.example.com</code>）</li><li>给内网域名签发证书</li></ul><p>在控制面的环境变量中配置：</p><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ACME_DNS_PROVIDER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=cf</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CF_TOKEN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=your-cloudflare-api-token</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>两个变量都配置且非空时，DNS-01 才会启用。</p><h3 id="获取-cloudflare-api-token" tabindex="-1">获取 Cloudflare API Token <a class="header-anchor" href="#获取-cloudflare-api-token" aria-label="Permalink to &quot;获取 Cloudflare API Token&quot;">​</a></h3><ol><li>登录 <a href="https://dash.cloudflare.com" target="_blank" rel="noreferrer">Cloudflare Dashboard</a></li><li>进入 <strong>My Profile → API Tokens → Create Token</strong>，选 Custom Token</li><li>配置权限：</li></ol><table tabindex="0"><thead><tr><th>权限</th><th>用途</th></tr></thead><tbody><tr><td>区域 / 区域 / 读取</td><td>读取域名区域信息</td></tr><tr><td>区域 / DNS / 读取</td><td>读取现有 DNS 记录</td></tr><tr><td>区域 / DNS / 编辑</td><td>创建和删除验证用的临时记录</td></tr></tbody></table><ol start="4"><li>区域资源选 <strong>特定区域 / 你的域名</strong></li><li>不限制客户端 IP</li></ol><p><img src="`+n+'" alt="Cloudflare API Token 权限"></p><p>Token 支持多种环境变量名，按优先级依次尝试：<code>CLOUDFLARE_DNS_API_TOKEN</code> &gt; <code>CF_DNS_API_TOKEN</code> &gt; <code>CF_TOKEN</code> &gt; <code>CF_Token</code>。填任意一个即可，同时设置了多个时优先级高的生效。</p><div class="warning custom-block"><p class="custom-block-title">Token 安全</p><p>CF_TOKEN 能操作 DNS 记录，不要提交到仓库。定期轮换 Token。更多安全建议见 <a href="./../reference/security">安全最佳实践</a>。</p></div><h2 id="手动上传证书" tabindex="-1">手动上传证书 <a class="header-anchor" href="#手动上传证书" aria-label="Permalink to &quot;手动上传证书&quot;">​</a></h2><p>已有证书时直接上传：</p><ol><li>创建证书时把「证书来源」选为 <strong>手动上传</strong></li><li>填入证书 PEM、私钥 PEM，可选填 CA 链 PEM</li><li>自签证书需勾选「标记为自签名证书」</li></ol><div class="tip custom-block"><p class="custom-block-title">手动上传的证书不会自动续期</p><p>到期前需要手动更新。优先使用自动签发。</p></div><h2 id="relay-证书" tabindex="-1">Relay 证书 <a class="header-anchor" href="#relay-证书" aria-label="Permalink to &quot;Relay 证书&quot;">​</a></h2><p>Relay 监听器默认使用系统自动签发的 Relay CA 和监听证书。普通用户无需手动创建，也无需维护 Pin Set。只有特殊合规或安全要求时才需要手动配置。详见 <a href="./../reference/relay-internals">Relay 协议内幕</a>。</p><h2 id="自动续期" tabindex="-1">自动续期 <a class="header-anchor" href="#自动续期" aria-label="Permalink to &quot;自动续期&quot;">​</a></h2><p>Let&#39;s Encrypt 证书有效期 90 天。控制面每 24 小时检查一次，对临近到期的证书自动续期。</p><p>DNS-01 续期需要 CF_TOKEN 持续有效。Token 过期会导致续期失败。</p><h2 id="http-3" tabindex="-1">HTTP/3 <a class="header-anchor" href="#http-3" aria-label="Permalink to &quot;HTTP/3&quot;">​</a></h2><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NRE_HTTP3_ENABLED</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>开启后 HTTPS 入口同时支持 HTTP/3（QUIC），不影响 HTTP/1.1 和 HTTP/2。需要客户端和浏览器支持。</p>',39)])])}const g=e(o,[["render",d]]);export{k as __pageData,g as default};
